INSERT OR REPLACE INTO settings (key, value) VALUES ('about_team', '[{"name":"The Founder","role":"Athlete and Visionary","description":"I worked hard to build my physique, but regular gym wear didn’t reflect the effort I put into training. When I discovered compression wear, it completely changed how my physique looked. That experience inspired me to create Flextreme."},{"name":"The Design Team","role":"Performance Designers","description":"Our design philosophy is simple: athletes designing for athletes, creating gym wear that enhances performance and showcases the physique."},{"name":"The Community","role":"Our Growing Community","description":"The Flextreme community is built for people who train hard, push their limits, and support each other to become stronger every day."}]');